import { html } from 'https://cdn.jsdelivr.net/npm/lit@3.3.0/+esm';
import 'https://cdn.jsdelivr.net/npm/@lit-labs/virtualizer@2/+esm';
const list = document.createElement('lit-virtualizer'); // 铁律 4:只用 JS 创建
list.scroller = true; list.style.height = `${spec.height ?? 400}px`; list.items = data.items;
